function DropYardLogo({ size = 'default' }) {
  const sizes = { small: 'w-8 h-8', default: 'w-10 h-10', large: 'w-14 h-14' };
  return (
    <div className={`${sizes[size]} relative flex items-center justify-center`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <path d="M20 60 L50 85 L80 60 L80 75 Q50 95 20 75 Z" fill="#F59E0B" />
        <path d="M30 70 L45 82 L70 58" stroke="white" strokeWidth="6" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M50 10 L15 40 L15 35 L50 5 L85 35 L85 40 L50 10" fill="#059669" />
        <path d="M20 38 L50 12 L80 38 L80 65 L20 65 Z" fill="white" stroke="#059669" strokeWidth="4"/>
        <rect x="40" y="30" width="20" height="20" fill="#059669" rx="2" />
        <line x1="50" y1="30" x2="50" y2="50" stroke="white" strokeWidth="2" />
        <line x1="40" y1="40" x2="60" y2="40" stroke="white" strokeWidth="2" />
      </svg>
    </div>
  );
}

function DropYardWordmark({ className = '' }) {
  return <span className={`font-bold ${className}`}><span className="text-emerald-600">Drop</span><span className="text-amber-500">Yard</span></span>;
}

function DropCountdown() {
  const [time, setTime] = useState({ hours: 23, minutes: 45, seconds: 32 });
  
  useEffect(() => {
    const interval = setInterval(() => {
      setTime(prev => {
        let { hours, minutes, seconds } = prev;
        seconds--;
        if (seconds < 0) { seconds = 59; minutes--; }
        if (minutes < 0) { minutes = 59; hours--; }
        if (hours < 0) { hours = 47; minutes = 59; seconds = 59; }
        return { hours, minutes, seconds };
      });
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const pad = (n) => String(n).padStart(2, '0');

  return (
    <div className="flex items-center gap-1.5 font-mono text-sm">
      <span className="bg-emerald-900/60 px-1.5 py-0.5 rounded text-white font-bold">{pad(time.hours)}</span>
      <span className="text-emerald-300 font-bold">:</span>
      <span className="bg-emerald-900/60 px-1.5 py-0.5 rounded text-white font-bold">{pad(time.minutes)}</span>
      <span className="text-emerald-300 font-bold">:</span>
      <span className="bg-emerald-900/60 px-1.5 py-0.5 rounded text-white font-bold">{pad(time.seconds)}</span>
    </div>
  );
}

